// src/Menu.js
import React, { useState, useEffect } from 'react';
import axios            from 'axios';
import './Menu.css';

const Menu = () => {
    const [menuItems, setMenuItems] = useState([]);
    const [loading,   setLoading]   = useState(true);
    const [error,     setError]     = useState(null);

    // editMode, priceMap voor drafts, en toDelete voor gemarkeerde deletions
    const [editMode,  setEditMode]  = useState(false);
    const [priceMap,  setPriceMap]  = useState({});
    const [toDelete,  setToDelete]  = useState(new Set());

    // haal menu op
    useEffect(() => {
        const fetchMenu = async () => {
            try {
                const res = await axios.get('http://localhost:3007/api/menu-items', {
                    withCredentials: true
                });
                setMenuItems(res.data);
            } catch (err) {
                console.error(err);
                setError('Kon menu‐items niet laden');
            } finally {
                setLoading(false);
            }
        };
        fetchMenu();
    }, []);

    // seed priceMap wanneer editMode aan gaat
    useEffect(() => {
        if (editMode) {
            const m = {};
            menuItems.forEach(i => {
                m[i.id_menu_item] = i.price;
            });
            setPriceMap(m);
            setToDelete(new Set());  // reset deletions
        }
    }, [editMode, menuItems]);

    if (loading) return <p>Loading menu…</p>;
    if (error)   return <p className="error">{error}</p>;

    // prijs wijzigen in draft
    const handlePriceChange = (id, raw) => {
        const v = parseFloat(raw);
        setPriceMap(pm => ({
            ...pm,
            [id]: isNaN(v) ? raw : v
        }));
    };

    // markeer / demarkeer voor verwijderen
    const toggleDelete = id => {
        setToDelete(td => {
            const nxt = new Set(td);
            nxt.has(id) ? nxt.delete(id) : nxt.add(id);
            return nxt;
        });
    };

    // Cancel: gooi draft weg
    const handleCancel = () => {
        setEditMode(false);
        setPriceMap({});
        setToDelete(new Set());
    };

    // Confirm: eerst deletions, dan price-updates
    const handleSave = async () => {
        try {
            // 1) DELETE gemarkeerde items
            for (let id of toDelete) {
                await axios.delete(
                    `http://localhost:3007/api/menu-items/${id}`,
                    { withCredentials: true }
                );
            }

            // 2) PATCH prijzen voor overgebleven items
            const updates = Object.entries(priceMap)
                .filter(([id,_]) => !toDelete.has(Number(id)))
                .map(([id, price]) => ({
                    id_menu_item: Number(id),
                    price:        Number(price)
                }));

            if (updates.length) {
                await axios.patch(
                    'http://localhost:3007/api/menu-items',
                    { updates },
                    { withCredentials: true }
                );
            }

            // 3) opnieuw inladen en exit editMode
            const res = await axios.get('http://localhost:3007/api/menu-items', {
                withCredentials: true
            });
            setMenuItems(res.data);
            setEditMode(false);
            setToDelete(new Set());
        } catch (err) {
            console.error('Er ging iets mis bij opslaan:', err);
            alert('Opslaan mislukt. Probeer opnieuw.');
        }
    };

    // groepeer per categorie, en filter items die gemarkeerd zijn
    const grouped = menuItems.reduce((acc, item) => {
        if (!acc[item.category]) acc[item.category] = [];
        acc[item.category].push(item);
        return acc;
    }, {});

    return (
        <div className="menu-container">
            <div className="menu-header">
                {!editMode ? (
                    <button
                        className="edit-save-btn"
                        onClick={() => setEditMode(true)}
                    >
                        Edit
                    </button>
                ) : (
                    <>
                        <button
                            className="edit-save-btn"
                            onClick={handleSave}
                        >
                            Confirm
                        </button>
                        <button
                            className="edit-cancel-btn"
                            onClick={handleCancel}
                        >
                            Cancel
                        </button>
                    </>
                )}
            </div>

            <div className="menu-list-container">
                {Object.entries(grouped).map(([category, items]) => (
                    <section key={category} className="menu-section">
                        <h3 className="menu-category">{category}</h3>
                        <ul className="menu-list">
                            {items.map(i => {
                                // skip als het item in toDelete zit
                                if (editMode && toDelete.has(i.id_menu_item)) return null;
                                return (
                                    <li key={i.id_menu_item} className="menu-item">
                                        {editMode && (
                                            <button
                                                className="delete-marker"
                                                onClick={() => toggleDelete(i.id_menu_item)}
                                                title="Verwijder dit item"
                                            >
                                                ×
                                            </button>
                                        )}
                                        <div className="item-name">{i.item_name}</div>
                                        <div className="item-brand">{i.producent}</div>
                                        <div className="item-price">
                                            {editMode ? (
                                                <div className="price-input-wrapper">
                                                    <span className="currency-symbol">€</span>
                                                    <input
                                                        type="number"
                                                        step="0.01"
                                                        className="menu-item-input"
                                                        value={priceMap[i.id_menu_item] ?? ''}
                                                        onChange={e =>
                                                            handlePriceChange(
                                                                i.id_menu_item,
                                                                e.target.value
                                                            )
                                                        }
                                                    />
                                                </div>
                                            ) : (
                                                `€${Number(i.price).toFixed(2)}`
                                            )}
                                        </div>
                                    </li>
                                );
                            })}
                        </ul>
                    </section>
                ))}
            </div>
        </div>
    );
};

export default Menu;
